import anthropic
import functools
from dataclasses import dataclass, field

client = anthropic.Anthropic()

@dataclass
class RateLimitedToolRegistry:
    """
    Wraps tool implementations with per-tool rate limiters.
    Pass this to the agent dispatch loop.
    """
    _tools: dict = field(default_factory=dict)
    _limiters: dict = field(default_factory=dict)

    def register(
        self,
        name: str,
        fn,
        capacity: int,
        rate: float,
    ):
        self._tools[name] = fn
        self._limiters[name] = TokenBucketRateLimiter(capacity, rate)

    def call(self, name: str, inputs: dict) -> str:
        limiter = self._limiters.get(name)
        if limiter and not limiter.acquire(block=True, timeout=5.0):
            return f"Rate limit exceeded for '{name}'. Retry in a moment."
        fn = self._tools.get(name)
        if fn is None:
            return f"Unknown tool: {name}"
        return fn(inputs)

# Tool implementations
def web_search(inputs: dict) -> str:
    query = inputs["query"]
    return f"(results for: {query})"

def send_notification(inputs: dict) -> str:
    return f"Notified: {inputs['message']}"

registry = RateLimitedToolRegistry()
# Max 3 searches/second, burst of 5
registry.register("web_search", web_search, capacity=5, rate=3.0)
# Max 1 notification every 2 seconds, no burst
registry.register("send_notification", send_notification, capacity=1, rate=0.5)

TOOLS = [
    {
        "name": "web_search",
        "description": "Search the web.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
    {
        "name": "send_notification",
        "description": "Send a notification.",
        "input_schema": {
            "type": "object",
            "properties": {"message": {"type": "string"}},
            "required": ["message"],
        },
    },
]

def run_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]
    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if hasattr(b, "text")), "")
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                output = registry.call(block.name, block.input)
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output,
                })
        messages.append({"role": "user", "content": results})

print(run_agent("Search for the latest AI news."))

class CallBudget:
    """
    Tracks total tool calls for one agent run.
    Raises RuntimeError when the budget is exhausted.
    """
    def __init__(self, max_calls: int):
        self.max_calls = max_calls
        self._count = 0

    def consume(self, tool_name: str):
        self._count += 1
        if self._count > self.max_calls:
            raise RuntimeError(
                f"Agent call budget exhausted after {self.max_calls} tool calls. "
                f"Last call was '{tool_name}'."
            )

    @property
    def remaining(self) -> int:
        return max(0, self.max_calls - self._count)

def run_agent_with_budget(task: str, max_calls: int = 20) -> str:
    budget = CallBudget(max_calls)
    messages = [{"role": "user", "content": task}]
    try:
        while True:
            resp = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=512,
                tools=TOOLS,
                messages=messages,
            )
            if resp.stop_reason == "end_turn":
                return next((b.text for b in resp.content if hasattr(b, "text")), "")
            messages.append({"role": "assistant", "content": resp.content})
            results = []
            for block in resp.content:
                if block.type == "tool_use":
                    budget.consume(block.name)
                    output = registry.call(block.name, block.input)
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": output,
                    })
            messages.append({"role": "user", "content": results})
    except RuntimeError as e:
        return f"Stopped: {e}"

result = run_agent_with_budget("Search for and summarize 50 papers on LLMs.", max_calls=10)
print(result)
# Stopped: Agent call budget exhausted after 10 tool calls. Last call was 'web_search'.

import time
import random

class RateLimitError(Exception):
    """Raised when a downstream API returns HTTP 429."""
    def __init__(self, retry_after: float | None = None):
        self.retry_after = retry_after

def call_with_backoff(
    fn,
    *args,
    max_retries: int = 5,
    base_delay: float = 1.0,
    max_delay: float = 60.0,
    **kwargs,
):
    """
    Call fn(*args, **kwargs) with exponential backoff on RateLimitError.
    Adds jitter to avoid thundering herd when multiple agents back off together.
    """
    for attempt in range(max_retries + 1):
        try:
            return fn(*args, **kwargs)
        except RateLimitError as e:
            if attempt == max_retries:
                raise
            if e.retry_after is not None:
                # Respect the API's Retry-After header
                delay = e.retry_after
            else:
                # Exponential: 1s, 2s, 4s, 8s, 16s (capped at max_delay)
                delay = min(base_delay * (2 ** attempt), max_delay)
            # Add jitter: ±20% of the delay
            jitter = delay * 0.2 * (random.random() * 2 - 1)
            sleep_time = max(0.0, delay + jitter)
            print(f"Rate limited. Retrying in {sleep_time:.1f}s (attempt {attempt + 1}/{max_retries})")
            time.sleep(sleep_time)

# Example: wrapping an API call that may return 429
call_count = 0
def flaky_api_call(query: str) -> str:
    global call_count
    call_count += 1
    if call_count < 3:
        raise RateLimitError(retry_after=0.1)  # Simulated 429 with Retry-After: 0.1
    return f"Result for: {query}"

result = call_with_backoff(flaky_api_call, "LLM safety research")
print(result)  # Result for: LLM safety research (after 2 retries)

import time
from dataclasses import dataclass, field
from collections import defaultdict

@dataclass
class RateLimitEvent:
    tool_name: str
    event_type: str   # "throttled" | "budget_exhausted" | "denied"
    timestamp: float
    agent_id: str

class RateLimitObserver:
    """
    Collects rate limit events and provides summary statistics.
    In production, emit these events to your metrics system instead.
    """
    def __init__(self):
        self._events: list[RateLimitEvent] = []

    def record(self, tool_name: str, event_type: str, agent_id: str):
        self._events.append(RateLimitEvent(
            tool_name=tool_name,
            event_type=event_type,
            timestamp=time.monotonic(),
            agent_id=agent_id,
        ))

    def summary(self) -> dict:
        counts = defaultdict(lambda: defaultdict(int))
        for e in self._events:
            counts[e.tool_name][e.event_type] += 1
        return {tool: dict(types) for tool, types in counts.items()}

observer = RateLimitObserver()

class ObservedRateLimitedRegistry(RateLimitedToolRegistry):
    """Extends the registry to emit events for every rate limit hit."""
    def __init__(self, obs: RateLimitObserver, agent_id: str):
        super().__init__()
        self._obs = obs
        self._agent_id = agent_id

    def call(self, name: str, inputs: dict) -> str:
        limiter = self._limiters.get(name)
        if limiter and not limiter.try_acquire():
            self._obs.record(name, "throttled", self._agent_id)
            # Block until token available (up to 5s)
            if not limiter.acquire(block=True, timeout=5.0):
                self._obs.record(name, "denied", self._agent_id)
                return f"Rate limit exceeded for '{name}'."
        fn = self._tools.get(name)
        if fn is None:
            return f"Unknown tool: {name}"
        return fn(inputs)

# Usage
obs = RateLimitObserver()
reg = ObservedRateLimitedRegistry(obs, agent_id="researcher-1")
reg.register("web_search", web_search, capacity=2, rate=1.0)

# Rapid calls — some will be throttled
for _ in range(5):
    reg.call("web_search", {"query": "LLM safety"})

print(obs.summary())
# {"web_search": {"throttled": 3}}
